8	export async function createDomain(input: unknown): Promise<ActionResult<{ id: number }>> {
9	  await requireAdmin()
10	  const parsed = domainSaveSchema.safeParse(input)
11	  if (!parsed.success) return { success: false, error: '입력값이 올바르지 않습니다', code: 'VALIDATION_ERROR' }
12	
13	  const domain = await prisma.domain.create({ data: parsed.data })
14	  revalidatePath('/domain')
15	  return { success: true, data: { id: domain.id } }
16	}
